<?php
use App\Core\Csrf;use App\Core\Router;use App\Core\View;
$money=static fn(mixed $v):string=>'R$ '.number_format((float)$v,2,',','.');$date=static function(?string $v):string{if(!$v)return '—';$t=strtotime($v);return $t?date('d/m/Y H:i',$t):$v;};
$statusLabel=['active'=>'Ativo','inactive'=>'Inativo','sandbox'=>'Teste','production'=>'Produção','open'=>'Aberta','paid'=>'Paga','overdue'=>'Em atraso','cancelled'=>'Cancelada','success'=>'Sucesso','error'=>'Erro','ignored'=>'Ignorado'];
$active=count(array_filter($gateways,static fn(array $g):bool=>($g['status']??'')==='active'));$production=count(array_filter($gateways,static fn(array $g):bool=>($g['environment']??'')==='production'));$failedEvents=count(array_filter($events,static fn(array $e):bool=>($e['status']??'')==='error'));$openInvoices=count(array_filter($invoices,static fn(array $i):bool=>in_array(($i['status']??''),['open','overdue'],true)));
$webhookFor=static function(string $provider):string{return match($provider){'asaas'=>Router::url('/webhooks/payments/asaas'),'mercadopago'=>Router::url('/webhooks/payments/mercadopago'),'stripe'=>Router::url('/webhooks/payments/stripe'),'pagbank'=>Router::url('/webhooks/payments/pagbank'),default=>'Manual'};};
?>
<section class="admin-module-hero"><div><span class="eyebrow">Financeiro SaaS</span><h2>Gateways de pagamento</h2><p>Centralize provedores, ambientes, métodos e webhooks com as credenciais protegidas.</p></div><button class="btn btn-primary" type="button" data-gateway-open="new" data-toggle-panel="gateway-drawer">Novo gateway</button></section>
<section class="admin-module-summary"><article><span>Total</span><strong><?= count($gateways) ?></strong><small>provedores configurados</small></article><article class="is-success"><span>Ativos</span><strong><?= $active ?></strong><small>disponíveis para cobrança</small></article><article class="is-blue"><span>Produção</span><strong><?= $production ?></strong><small>configurações reais</small></article><article class="is-warning"><span>Falhas recentes</span><strong><?= $failedEvents ?></strong><small><?= $openInvoices ?> cobranças pendentes</small></article></section>
<section class="card admin-module-panel"><div class="section-heading admin-module-heading"><div><span class="eyebrow">Provedores configurados</span><h2>Contas de pagamento</h2><p>Abra a edição somente quando precisar trocar uma chave ou configuração.</p></div><span class="badge"><?= count($gateways) ?> gateway(s)</span></div><div class="admin-module-card-list compact-cards"><?php foreach($gateways as $gateway):?><article class="admin-record-card"><div class="admin-record-main"><span class="admin-record-mark is-payment">$</span><div class="admin-record-copy"><div class="admin-record-title-row"><div><h3><?= View::e($gateway['label']) ?></h3><p><?= View::e($providerLabels[$gateway['provider']]??$gateway['provider']) ?></p></div><div class="admin-record-badges"><span class="badge badge-<?= View::e($gateway['status']) ?>"><?= View::e($statusLabel[$gateway['status']]??$gateway['status']) ?></span><?php if((int)$gateway['is_default']===1):?><span class="badge">Padrão</span><?php endif;?></div></div></div></div><dl class="admin-record-details"><div><dt>Ambiente</dt><dd><?= View::e($statusLabel[$gateway['environment']]??$gateway['environment']) ?></dd></div><div><dt>Método padrão</dt><dd><?= View::e($methodLabels[$gateway['default_payment_method']]??$gateway['default_payment_method']) ?></dd></div><div><dt>API</dt><dd><?= View::e($gateway['api_base_url']?:'Padrão do provedor') ?></dd></div><div><dt>Webhook</dt><dd><?= View::e($webhookFor($gateway['provider'])) ?></dd></div></dl><div class="admin-record-actions"><button class="btn btn-small btn-outline" type="button" data-toggle-panel="gateway-drawer" data-gateway-open="edit" data-id="<?= (int)$gateway['id'] ?>" data-label="<?= View::e($gateway['label']) ?>" data-provider="<?= View::e($gateway['provider']) ?>" data-environment="<?= View::e($gateway['environment']) ?>" data-status="<?= View::e($gateway['status']) ?>" data-api-base-url="<?= View::e($gateway['api_base_url']??'') ?>" data-public-key="<?= View::e($gateway['public_key']??'') ?>" data-method="<?= View::e($gateway['default_payment_method']) ?>" data-is-default="<?= (int)$gateway['is_default'] ?>" data-notes="<?= View::e(rawurlencode((string)($gateway['notes']??''))) ?>">Editar gateway</button></div></article><?php endforeach;?><?php if(!$gateways):?><div class="empty-state">Nenhum gateway cadastrado.</div><?php endif;?></div></section>
<div class="admin-dashboard-grid"><section class="card"><div class="section-heading"><div><span class="eyebrow">Cobranças recentes</span><h2>Links e pagamentos</h2></div><span class="badge"><?= count($invoices) ?> registro(s)</span></div><div class="admin-log-list"><?php foreach(array_slice($invoices,0,20) as $invoice):?><article class="admin-log-item"><div><strong><?= View::e($invoice['invoice_number']) ?> · <?= View::e($invoice['tenant_name']) ?></strong><span><?= View::e($money($invoice['amount'])) ?> · vence <?= View::e($date($invoice['due_date'])) ?></span><small><?= View::e($invoice['gateway_label']??'Sem gateway') ?></small></div><div><span class="badge badge-<?= View::e($invoice['status']) ?>"><?= View::e($statusLabel[$invoice['status']]??$invoice['status']) ?></span><?php $link=$invoice['external_checkout_url']?:$invoice['external_invoice_url'];if($link):?><a class="btn btn-small btn-outline" target="_blank" rel="noopener" href="<?= View::e($link) ?>">Abrir link</a><?php endif;?></div></article><?php endforeach;?><?php if(!$invoices):?><div class="empty-state">Nenhuma cobrança registrada.</div><?php endif;?></div></section><section class="card"><div class="section-heading"><div><span class="eyebrow">Retornos dos provedores</span><h2>Eventos de pagamento</h2></div><span class="badge"><?= count($events) ?> evento(s)</span></div><div class="admin-log-list"><?php foreach(array_slice($events,0,20) as $event):?><article class="admin-log-item is-<?= View::e($event['status']) ?>"><div><strong><?= View::e($event['gateway_label']??($providerLabels[$event['provider']??'']??'Gateway')) ?></strong><span><?= View::e($event['tenant_name']??'Sem empresa') ?> · <?= View::e($event['event_type']??'Evento') ?></span><small><?= View::e($date($event['created_at']??null)) ?></small></div><span class="badge badge-<?= View::e($event['status']) ?>"><?= View::e($statusLabel[$event['status']]??$event['status']) ?></span></article><?php endforeach;?><?php if(!$events):?><div class="empty-state">Nenhum evento recebido.</div><?php endif;?></div></section></div>
<aside class="conversation-details conversation-drawer admin-form-drawer" id="gateway-drawer" aria-label="Configurar gateway" aria-modal="true" role="dialog"><div class="conversation-drawer-header"><div><span class="eyebrow" data-gateway-eyebrow>Novo gateway</span><h2 data-gateway-title>Configurar pagamento</h2><p>As chaves serão criptografadas e não voltarão a ser exibidas.</p></div><button class="icon-button drawer-close" type="button" data-close-panel="gateway-drawer">×</button></div><div class="conversation-drawer-body"><form class="drawer-form" method="post" action="<?= View::e(Router::url('/payment-gateways/save')) ?>" data-gateway-form><?= Csrf::input() ?><input type="hidden" name="id" value="0" data-gateway-field="id"><section class="drawer-section"><div class="drawer-section-title"><div><span class="eyebrow">1. Provedor</span><h3>Identificação e ambiente</h3></div></div><div class="drawer-form-grid"><label class="field drawer-span"><span>Nome interno</span><input name="label" data-gateway-field="label" placeholder="Asaas RS Produção" required></label><label class="field"><span>Provedor</span><select name="provider" data-gateway-field="provider"><?php foreach($providerLabels as $key=>$label):?><option value="<?= View::e($key) ?>"><?= View::e($label) ?></option><?php endforeach;?></select></label><label class="field"><span>Ambiente</span><select name="environment" data-gateway-field="environment"><option value="production">Produção</option><option value="sandbox">Teste / sandbox</option></select></label><label class="field"><span>Método padrão</span><select name="default_payment_method" data-gateway-field="method"><?php foreach($methodLabels as $key=>$label):?><option value="<?= View::e($key) ?>"><?= View::e($label) ?></option><?php endforeach;?></select></label><label class="field"><span>Situação</span><select name="status" data-gateway-field="status"><option value="active">Ativo</option><option value="inactive">Inativo</option></select></label></div></section><section class="drawer-section"><div class="drawer-section-title"><div><span class="eyebrow">2. Credenciais</span><h3>Acesso à API</h3></div></div><div class="drawer-form-grid"><label class="field drawer-span"><span>URL base da API</span><input name="api_base_url" data-gateway-field="api_base_url" placeholder="Deixe vazio para usar o padrão"></label><label class="field drawer-span"><span data-gateway-key-label>API Key / Access Token</span><input name="api_key" type="password" data-gateway-field="api_key"><small class="field-hint" data-gateway-key-hint>Informe a chave do provedor.</small></label><label class="field drawer-span"><span>Chave pública / identificador</span><input name="public_key" data-gateway-field="public_key"></label><label class="field drawer-span"><span>Token interno do webhook</span><input name="webhook_secret" type="password" data-gateway-field="webhook_secret"><small class="field-hint">Opcional; deixe vazio na edição para manter.</small></label></div></section><section class="drawer-section"><div class="drawer-form-grid"><label class="check-field drawer-span"><input type="checkbox" name="is_default" value="1" data-gateway-field="is_default"><span>Usar como gateway padrão</span></label><label class="field drawer-span"><span>Observações</span><textarea name="notes" rows="4" data-gateway-field="notes"></textarea></label></div></section><div class="drawer-savebar"><button class="btn btn-quiet" type="button" data-close-panel="gateway-drawer">Cancelar</button><button class="btn btn-primary" type="submit" data-gateway-submit>Salvar gateway</button></div></form></div></aside>
